import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

export default function DestinationDetail() {
  const { id } = useParams();
  const [destination, setDestination] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`http://localhost:5000/destinations/${id}`)
      .then(res => res.json())
      .then(data => {
        console.log("Destination:", data);
        setDestination(data);
        setLoading(false);
      })
      .catch(err => console.error(err));
  }, [id]);

  if (loading) return <h2>Loading...</h2>;

  if (!destination) return <h2>No data found</h2>;

  return (
    <div style={{ padding: 20 }}>
      {/* HEADER */}
      <h1>{destination.name}</h1>
      <p>{destination.description}</p>

      {/* IMAGE (optional) */}
      {destination.image && (
        <img
          src={destination.image}
          alt={destination.name}
          style={{ width: "100%", maxWidth: 500, borderRadius: 10 }}
        />
      )}

      {/* DETAILS */}
      <div style={{ marginTop: 20 }}>
        <h3>Price</h3>
        <p>₹{destination.price}</p>
      </div>

      {/* SIMPLE ITINERARY */}
      <div style={{ marginTop: 30 }}>
        <h2>Suggested Plan</h2>

        <div>
          <h3>Day 1</h3>
          <ul>
            <li>Arrival & hotel check-in</li>
            <li>Local sightseeing</li>
            <li>Dinner</li>
          </ul>
        </div>

        <div>
          <h3>Day 2</h3>
          <ul>
            <li>Main attractions</li>
            <li>Food exploration</li>
            <li>Shopping</li>
          </ul>
        </div>

        <div>
          <h3>Day 3</h3>
          <ul>
            <li>Relaxation</li>
            <li>Return journey</li>
          </ul>
        </div>
      </div>

      {/* BUTTON */}
      <button
        style={{
          marginTop: 30,
          padding: "10px 20px",
          background: "#1D9E75",
          color: "#fff",
          border: "none",
          borderRadius: 8
        }}
      >
        Plan Trip →
      </button>
    </div>
  );
}
